-- в”Ђв”Ђ acunote.com в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Acunote is a longstanding online project management and Scrum tool from Pluron Inc, offering sprint boards, burndown charts, and wiki-based collaboration for agile software teams, though it is a small, lower-profile product with limited recent public activity.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 5 users; paid plans start at 49 dollars per month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Very small team, reported as approximately 1 employee as of 2026$q$, company_size),
  headquarters = COALESCE($q$Foster City, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Acunote Review 2026: Scrum Project Management Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Acunote is an agile project management and Scrum tool with burndown charts and sprint tracking. See pricing, features, pros, cons, and how active it still is.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Acunote is an online project management and Scrum software product built by Pluron Inc, a small, self-funded, bootstrapped software company headquartered in Foster City, California, in Silicon Valley. Sources give conflicting founding dates, with some indicating the company was incorporated around 2006 and others citing 2011, so an exact founding year cannot be confirmed with confidence. Acunote positions itself as agile project management software usable by organizations of any size, from small teams up to enterprises, and is designed to serve as a company-wide tool for tracking software development, IT projects, and general team collaboration rather than only engineering-specific work. Its core functionality centers on Scrum: teams create projects and sprints, assign and track tasks from a central task list screen, and monitor progress through burndown charts that are generated from actual logged work rather than manual updates, aiming to give more accurate forecasts of sprint and project completion. Each project and task includes an integrated wiki with a rich text editor for documentation and collaboration. Acunote supports role-based access control and offers different levels of analytics and reporting depending on plan tier, ranging from basic sprint-level analytics to enterprise-wide reporting across multiple departments. Historically, Acunote emphasized integrations with widely used developer tools of its era, including source control systems such as Subversion, GitHub, Bitbucket, and Perforce, and bug trackers such as JIRA, Trac, FogBugz, Bugzilla, and Mantis, as well as a listing in the Google Workspace Marketplace as a Scrum project management add-on for G Suite. Pricing follows a freemium model: a free plan supports individuals or small teams of up to 5 users, while paid plans, Business at 49 dollars per month, Corporate at 99 dollars per month, and Enterprise at 149 dollars per month, each include 7 users with additional users billed incrementally, plus a 30-day free trial and no long-term contract requirement. Independent company-data sources report that Acunote and Pluron Inc currently operate with a very small team, cited as roughly a single employee as of 2026, which is a notable decline from prior years and suggests the product is maintained in a low-overhead, largely legacy mode rather than under active growth or heavy new feature development. The website remains online and accessible, with login and marketing pages functioning, but the presence of dated integrations like Subversion and Trac, alongside minimal visible recent updates, indicates limited current development activity. Prospective buyers should treat Acunote as a stable but low-profile legacy tool rather than an actively evolving modern SaaS product, and should verify current support responsiveness directly before committing a team to it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d6d4025-1392-4d58-abe6-a85b1348c75f';

